### Step 1: Set Up the Project

Create a new directory for your project and initialize it:

```bash
mkdir blog-app
cd blog-app
npm init -y
```

Install the necessary packages:

```bash
npm install express mongoose body-parser cors dotenv
```

### Step 2: Create Configuration Files

Create a `.env` file to store your MongoDB connection string:

```
MONGODB_URI=mongodb+srv://<username>:<password>@cluster0.mongodb.net/blog?retryWrites=true&w=majority
```

And create a `config.js` file to manage configuration:

```javascript
require('dotenv').config();

const dbConfig = {
  uri: process.env.MONGODB_URI,
  host: 'localhost',
  port: 27017,
};

module.exports = dbConfig;
```

### Step 3: Set Up the Express Application

Create an `index.js` file to set up the server:

```javascript
const express = require('express');
const bodyParser = require('body-parser');
const cors = require('cors');
const mongoose = require('mongoose');
const app = express();

app.use(bodyParser.json());
app.use(cors());

// Connect to MongoDB
mongoose.connect(dbConfig.uri, {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});

// Define the Post model
const PostSchema = new mongoose.Schema({
  title: String,
  content: String,
  createdAt: Date,
});

const Post = mongoose.model('Post', PostSchema);

// Routes

// Get all posts
app.get('/posts', async (req, res) => {
  try {
    const result = await Post.find();
    res.json(result.docs);
  } catch (err) {
    res.status(500).json({ error: err.stack });
  }
});

// Create a new post
app.post('/posts', async (req, res) => {
  try {
    const result = await Post.create(req.body);
    res.status(201).json(result.doc);
  } catch (err) {
    res.status(400).json({ error: err.stack });
  }
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
```

### Step 4: Run the Application

Start your application by running:

```bash
node index.js
```

